script.text:
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onTabChanged);
  f._tabContainer._loaded = true;
}
function close$VoucherFilter$(f) {
  try {f.remove_activeTabChanged(onTabChanged);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
}
function onTabChanged(f, e) {f.parentForm.focusWhenTabChanged(['ma_vtr', 'ma_kenh']);}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, k = new Array();
      g._refreshMemvars = true;
      g._dot = f.getItemValue('ma_dot');
      g._hs = f.getItemValue('ma_hs');
      g._ten = f.getItemValue('ten');
      g._vtr = f.getItemValue('ma_vtr');
      g._bp = f.getItemValue('ma_bp');
      g._tths = f.getItemValue('ma_tt');
      g._d1 = f.getItemValue('ngay_nop1');
      g._d2 = f.getItemValue('ngay_nop2');
      g._gt = f.getItemValue('gioi_tinh');
      g._cmnd = f.getItemValue('cmnd_so');
      g._qt = f.getItemValue('quoc_tich');
      g._hn = f.getItemValue('hon_nhan');
      g._kenh = f.getItemValue('ma_kenh');
      g._nguon = f.getItemValue('ma_nguon');
      g._tt = f.getItemValue('status');

      if (g._dot) Array.add(k, {Name: 'ma_dot', Opr: 'like', Value: g._dot += '%', Type: 'String', Ignore: false});
      if (g._hs) Array.add(k, {Name: 'ma_hs', Opr: 'like', Value: g._hs += '%', Type: 'String', Ignore: false});
      if (g._ten) Array.add(k, {Name: 'ten', Opr: 'like', Value: '%' + g._ten + '%', Type: 'String', Ignore: false});
      if (g._vtr) Array.add(k, {Name: 'ma_vtr', Opr: '=', Value: g._vtr, Type: 'String', Ignore: false});
      if (g._bp) Array.add(k, {Name: 'ma_bp', Opr: '=', Value: g._bp, Type: 'String', Ignore: false});
      if (g._tths) Array.add(k, {Name: 'ma_tt', Opr: 'like', Value: g._tths += '%', Type: 'String', Ignore: false});
      if (g._d1) Array.add(k, {Name: 'ngay_nop', Opr: '>=', Value: g._d1, Type: 'DateTime', Ignore: false});
      if (g._d2) Array.add(k, {Name: 'ngay_nop', Opr: '<=', Value: g._d2, Type: 'DateTime', Ignore: false});
      if (g._gt != '*') Array.add(k, {Name: 'gioi_tinh', Opr: '=', Value: g._gt, Type: 'String', Ignore: false});
      if (g._cmnd) Array.add(k, {Name: 'cmnd_so', Opr: 'like', Value: g._cmnd += '%', Type: 'String', Ignore: false});
      if (g._qt) Array.add(k, {Name: 'quoc_tich', Opr: 'like', Value: g._qt += '%', Type: 'String', Ignore: false});
      if (g._hn) Array.add(k, {Name: 'ma_tthn', Opr: 'like', Value: g._hn += '%', Type: 'String', Ignore: false});
      if (g._kenh) Array.add(k, {Name: 'ma_kenh', Opr: 'like', Value: g._kenh += '%', Type: 'String', Ignore: false});
      if (g._nguon) Array.add(k, {Name: 'ma_nguon', Opr: 'like', Value: g._nguon += '%', Type: 'String', Ignore: false});
      if (g._tt != '*') Array.add(k, {Name: 'status', Opr: '=', Value: g._tt, Type: 'String', Ignore: false});
      g.set_externalKey(k);
      break;
    default:
      break;
  }
}
/* </flatten> */
